#include <limits.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    int *na = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &na[i]);
    }

    int *ma = (int *)malloc(m * sizeof(int));
    for (int i = 0; i < m; i++) {
        scanf("%d", &ma[i]);
    }

    int min_intersection = INT_MAX;
    int found = 0;

